const __pageData = JSON.parse('{"title":"数据库迁移：从版本控制到零停机","description":"系统阐述数据库迁移的形式化定义、分类体系、零停机部署理论，以及 Prisma、Drizzle、TypeORM 等主流工具的工程实践","frontmatter":{"title":"数据库迁移：从版本控制到零停机","description":"系统阐述数据库迁移的形式化定义、分类体系、零停机部署理论，以及 Prisma、Drizzle、TypeORM 等主流工具的工程实践","date":"2026-05-01T00:00:00.000Z","tags":["database","migration","ORM","Prisma","Drizzle","TypeORM","zero-downtime","schema"],"category":"engineering"},"headers":[],"relativePath":"database-orm/04-database-migrations.md","filePath":"database-orm/04-database-migrations.md","lastUpdated":1777741461000}');
